    storyConsequence: { correct: { zh: '堤坝截面——面积正确！做得漂亮！', en: 'Embankment Cross-Section — Well done!' }, wrong: { zh: '面积数值偏了——再看看长和宽代入对了吗？', en: 'Not quite... Try again!' } }
