    skillName: { zh: '函数求值术', en: 'Function Evaluation' },
    skillSummary: { zh: '代入 x 求 y', en: 'Substitute x to find y' },
    story: { zh: '诸葛亮改良连弩。射程函数 $y = mx + c$，代入特定角度求射程。', en: 'Zhuge Liang improves the crossbow. Range function $y = mx + c$, find range at specific angle.' },
    description: { zh: '求函数在给定 $x$ 处的值。', en: 'Find the function value at the given $x$.' },
