    storyConsequence: { correct: { zh: '战损评估——百分比算得好！做得漂亮！', en: 'Battle Casualties — Well done!' }, wrong: { zh: '百分比差一点——记住要除以 100 再乘哦。', en: 'Not quite... Try again!' } }
