    skillName: { zh: '两点间距离术', en: 'Distance Formula' },
    skillSummary: { zh: 'd = √((x2-x1)² + (y2-y1)²)', en: 'd = √((x2-x1)² + (y2-y1)²)' },
    story: { zh: '两座营寨的坐标已知。求两营之间的直线距离——本质就是勾股定理！', en: 'Coordinates of two camps are known. Find the straight-line distance — essentially Pythagoras!' },
    description: { zh: '求两点间距离，输入 $x$ = 距离值。', en: 'Find distance between two points. Enter $x$ = distance value.' },
