    tutorialSteps: [
      { text: { zh: '庞统：为什么要用列联表？\n军队情报复杂——男女、有无眼镜、老中青……列联表把所有信息整理成格子，一目了然！\n从表中直接读取条件概率。', en: 'Pang Tong: "Why use two-way tables?\nMilitary intel is complex — gender, glasses, age... A two-way table organizes everything into cells, clear at a glance!\nRead conditional probabilities directly from the table."' }, highlightField: 'ans' },
      { text: { zh: '庞统：条件概率公式\n$$P(A|B) = \\frac{P(A \\cap B)}{P(B)}$$\n翻译：已知B发生，A也发生的概率 = 两者同时发生 ÷ B发生', en: 'Pang Tong: "Conditional probability formula\n$$P(A|B) = \\frac{P(A \\cap B)}{P(B)}$$\nTranslation: given B happened, probability of A = both happen ÷ B happens"' }, highlightField: 'ans' },
      { text: { zh: '庞统：从表中读数\n戴眼镜的总人数 = 20 + 15 = 35\n其中男生 = 20', en: 'Pang Tong: "Read from table\nTotal with glasses = 20 + 15 = 35\nOf those, male = 20"' }, highlightField: 'ans' },
      { text: { zh: '庞统：计算条件概率\nP(男|戴眼镜) = $\\frac{20}{35}$\n化简：$\\frac{20}{35} = \\frac{4}{7}$（两边除以5）', en: 'Pang Tong: "Calculate conditional probability\nP(male | glasses) = $\\frac{20}{35}$\nSimplify: $\\frac{20}{35} = \\frac{4}{7}$ (divide both by 5)"' }, highlightField: 'ans' },
      { text: { zh: '庞统：答案\n$\\frac{20}{35} = \\frac{4}{7}$，分子 = 4。', en: 'Pang Tong: "Answer\n$\\frac{20}{35} = \\frac{4}{7}$, numerator = 4."' }, highlightField: 'ans' },
      { text: { zh: '庞统：验算\n$4 \\times 5 = 20$ ✓，$7 \\times 5 = 35$ ✓\n$\\gcd(20, 35) = 5$，化简正确！', en: 'Pang Tong: "Verify\n$4 \\times 5 = 20$ ✓, $7 \\times 5 = 35$ ✓\n$\\gcd(20, 35) = 5$, simplification correct!"' }, highlightField: 'ans' },
    ],
    secret: { concept: { zh: '条件概率 P(A|B) = 同时满足AB的数量 ÷ 满足B的总数。', en: 'Conditional probability P(A|B) = count of both A and B ÷ total count of B.' }, formula: '$P(A|B) = \\frac{n(A \\cap B)}{n(B)}$', tips: [{ zh: '庞统提示：条件概率——分母是"已知条件"的总数。', en: 'Pang Tong Tip: Conditional probability — denominator is the total of the "given condition".' }] },
    storyConsequence: { correct: { zh: '列联表概率——条件概率精准！做得漂亮！', en: 'Two-Way Table — Well done!' }, wrong: { zh: '分母是戴眼镜的总人数——是多少？', en: 'Denominator is total glasses-wearers — how many?' } }
