    title: { zh: '圆锥体积', en: 'Cone Volume' },
    skillName: { zh: '锥体体积术', en: 'Cone Volume' },
    skillSummary: { zh: '$V = \\frac{1}{3}\\pi r^2 h$', en: '$V = \\frac{1}{3}\\pi r^2 h$' },
